mapper.select:
SELECT 
	COUNT(1) departmentNum
FROM 
	company_department a 
WHERE a.company_id = #{id}

	AND a.tenant_id = #{tenantId}

SELECT a.id, a.`name` title, a.p_id parentId, '[{"type": "0", "isChecked": "0"}]' checkArr FROM company_mation a
AND a.tenant_id = #{tenantId}
ORDER BY a.p_id ASC

SELECT a.id, a.`name`, a.p_id pId, 'isCompany' folderType, 1 isParent, '../../assets/images/icon/company-icon.png' `icon`, '' `email` FROM company_mation a
AND a.id = #{id}
AND a.tenant_id = #{tenantId}
